module thermal_sensor_calibration(  
    input [9:0] obf_temperature_in,  
    output reg [9:0] temperature_out  
);  
    always @(*) begin  
        if (obf_temperature_in < 10'd100)  
            temperature_out = obf_temperature_in;  
        else  
            temperature_out = obf_temperature_in - 10'd10;  
    end  
endmodule
